{
  "name": "قوام - QAWAM",
  "description": "أداة تخطيط مالي شخصي لتقسيم الراتب الشهري وفق أفضل الممارسات المالية (قاعدة 50/30/20). تعمل محلياً بالكامل."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ExpenseType {
  NEED = 'احتياج',
  WANT = 'رغبة',
  SAVING = 'ادخار واستثمار'
}

export interface Expense {
  id: string;
  name: string;
  amount: number;
  type: ExpenseType;
  notes?: string;
}

export interface Suggestion {
  name: string;
}

export interface DashboardMetrics {
  totalNeeds: number;
  totalWants: number;
  totalSavingsExpenses: number; // Savings explicitly listed as expenses
  totalExpenses: number;
  remainingSalary: number;
  totalSavingsCalculated: number; // (Salary - Needs - Wants)
}

import React from 'react';
import { DashboardMetrics } from '../types';

interface StickyHeaderProps {
  salary: number;
  metrics: DashboardMetrics;
}

export const StickyHeader: React.FC<StickyHeaderProps> = ({ salary, metrics }) => {
  const savingsPercentage = salary > 0 ? Math.round((metrics.totalSavingsCalculated / salary) * 100) : 0;

  return (
    <div className="sticky-header bg-white/90 border-b border-gray-200 shadow-sm py-4 px-4 mb-6">
      <div className="max-w-4xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-2">
           <span className="text-gray-500 font-medium">الراتب:</span>
           <span className="text-xl font-bold text-gray-900">{salary.toLocaleString()}</span>
        </div>

        <div className="flex gap-6 text-sm md:text-base">
          <div className="flex flex-col items-center">
            <span className="text-gray-500 text-xs">إجمالي المصارف</span>
            <span className={`font-bold ${metrics.totalExpenses > salary ? 'text-red-600' : 'text-gray-800'}`}>
              {metrics.totalExpenses.toLocaleString()}
            </span>
          </div>
          <div className="w-px h-8 bg-gray-300"></div>
          <div className="flex flex-col items-center">
            <span className="text-gray-500 text-xs">المتبقي (كاش)</span>
            <span className={`font-bold ${metrics.remainingSalary < 0 ? 'text-red-600' : 'text-green-600'}`}>
              {metrics.remainingSalary.toLocaleString()}
            </span>
          </div>
          <div className="w-px h-8 bg-gray-300"></div>
          <div className="flex flex-col items-center">
            <span className="text-gray-500 text-xs">نسبة الادخار الكلية</span>
            <span className={`font-bold ${savingsPercentage >= 20 ? 'text-green-600' : 'text-amber-600'}`}>
              %{savingsPercentage}
            </span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { DashboardMetrics, ExpenseType } from '../types';
import { COLORS } from '../constants';

interface FinancialChartProps {
  metrics: DashboardMetrics;
}

export const FinancialChart: React.FC<FinancialChartProps> = ({ metrics }) => {
  const data = [
    { name: ExpenseType.NEED, value: metrics.totalNeeds, color: COLORS[ExpenseType.NEED] },
    { name: ExpenseType.WANT, value: metrics.totalWants, color: COLORS[ExpenseType.WANT] },
    { name: 'ادخار كلي (مدخلات + متبقي)', value: metrics.totalSavingsCalculated, color: COLORS[ExpenseType.SAVING] },
  ].filter(item => item.value > 0);

  if (data.length === 0) {
    return (
      <div className="h-64 flex items-center justify-center bg-gray-50 rounded-lg border border-dashed border-gray-300 text-gray-400">
        أدخل الراتب والمصارف لرؤية المخطط
      </div>
    );
  }

  return (
    <div className="h-72 w-full" dir="ltr"> 
      {/* dir=ltr is forced here for Recharts tooltip positioning consistency, labels are Arabic */}
      <ResponsiveContainer width="100%" height="100%">
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            innerRadius={60}
            outerRadius={80}
            paddingAngle={5}
            dataKey="value"
          >
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} strokeWidth={0} />
            ))}
          </Pie>
          <Tooltip 
            formatter={(value: number) => [`${value.toLocaleString()}`, 'المبلغ']}
            contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
          />
          <Legend verticalAlign="bottom" height={36} />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
};

import React from 'react';
import { Trash2, Edit2 } from 'lucide-react';
import { Expense, ExpenseType } from '../types';
import { COLORS } from '../constants';

interface ExpenseTableProps {
  expenses: Expense[];
  salary: number;
  onDelete: (id: string) => void;
  onEdit: (expense: Expense) => void;
}

export const ExpenseTable: React.FC<ExpenseTableProps> = ({ expenses, salary, onDelete, onEdit }) => {

  const getPercentageColor = (amount: number): string => {
    if (salary === 0) return 'bg-gray-100 text-gray-500';
    const percentage = (amount / salary) * 100;
    if (percentage <= 5) return 'bg-green-100 text-green-800';
    if (percentage <= 15) return 'bg-amber-100 text-amber-800';
    return 'bg-red-100 text-red-800';
  };

  const getTypeBadge = (type: ExpenseType) => {
    switch (type) {
      case ExpenseType.NEED: return <span className="px-2 py-1 rounded-full text-xs bg-blue-100 text-blue-800 font-medium">احتياج</span>;
      case ExpenseType.WANT: return <span className="px-2 py-1 rounded-full text-xs bg-amber-100 text-amber-800 font-medium">رغبة</span>;
      case ExpenseType.SAVING: return <span className="px-2 py-1 rounded-full text-xs bg-emerald-100 text-emerald-800 font-medium">ادخار</span>;
    }
  };

  return (
    <div className="overflow-x-auto rounded-lg border border-gray-200">
      <table className="w-full text-sm text-right">
        <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
          <tr>
            <th className="px-4 py-3">اسم المصرف</th>
            <th className="px-4 py-3">النوع</th>
            <th className="px-4 py-3">المبلغ</th>
            <th className="px-4 py-3">النسبة</th>
            <th className="px-4 py-3">ملاحظات</th>
            <th className="px-4 py-3 text-center">إجراءات</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100 bg-white">
          {expenses.length === 0 ? (
            <tr>
              <td colSpan={6} className="px-4 py-8 text-center text-gray-400">
                لا توجد مصارف مضافة حالياً.
              </td>
            </tr>
          ) : (
            expenses.map((expense) => {
              const percentage = salary > 0 ? Math.ceil((expense.amount / salary) * 100) : 0;
              return (
                <tr key={expense.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-3 font-medium text-gray-900">{expense.name}</td>
                  <td className="px-4 py-3">{getTypeBadge(expense.type)}</td>
                  <td className="px-4 py-3 font-semibold">{expense.amount.toLocaleString()}</td>
                  <td className="px-4 py-3">
                    <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${getPercentageColor(expense.amount)}`}>
                      %{percentage}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-gray-500 max-w-xs truncate">{expense.notes || '-'}</td>
                  <td className="px-4 py-3 flex justify-center gap-2">
                    <button 
                      onClick={() => onEdit(expense)} 
                      className="p-1.5 text-blue-600 hover:bg-blue-50 rounded transition-colors"
                      title="تعديل"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => onDelete(expense.id)} 
                      className="p-1.5 text-red-600 hover:bg-red-50 rounded transition-colors"
                      title="حذف"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, ExpenseType } from '../types';
import { EXPENSE_TYPES, SUGGESTED_EXPENSES } from '../constants';
import { PlusCircle, Save, X, AlertTriangle } from 'lucide-react';

interface AddExpenseFormProps {
  salary: number;
  currentTotal: number;
  onAdd: (expense: Omit<Expense, 'id'>) => boolean; // returns true if success
  editingExpense?: Expense | null;
  onUpdate: (updatedExpense: Expense) => boolean;
  onCancelEdit: () => void;
}

export const AddExpenseForm: React.FC<AddExpenseFormProps> = ({ 
  salary, 
  currentTotal, 
  onAdd, 
  editingExpense,
  onUpdate,
  onCancelEdit
}) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [type, setType] = useState<ExpenseType>(ExpenseType.NEED);
  const [notes, setNotes] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [advice, setAdvice] = useState<string | null>(null);

  // Load editing expense data
  useEffect(() => {
    if (editingExpense) {
      setName(editingExpense.name);
      setAmount(editingExpense.amount.toString());
      setType(editingExpense.type);
      setNotes(editingExpense.notes || '');
      setError(null);
      setAdvice(null);
    }
  }, [editingExpense]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name || isNaN(numAmount) || numAmount <= 0) return;

    // Check budget limit (logic handled by parent, but we do a pre-check for feedback)
    const amountDiff = editingExpense ? numAmount - editingExpense.amount : numAmount;
    if (currentTotal + amountDiff > salary) {
      const deficit = (currentTotal + amountDiff) - salary;
      setError(`عفواً، إضافة هذا المبلغ ستتجاوز الراتب بمقدار ${deficit.toLocaleString()}.`);
      setAdvice(`توصية الخبير: لكي تتمكن من إضافة هذا المصرف، حاول تقليل بند من بنود "${ExpenseType.WANT}" بمقدار ${deficit.toLocaleString()}، أو أعد جدولة بنود "${ExpenseType.NEED}" غير الأساسية.`);
      return;
    }

    let success = false;
    if (editingExpense) {
      success = onUpdate({ ...editingExpense, name, amount: numAmount, type, notes });
    } else {
      success = onAdd({ name, amount: numAmount, type, notes });
    }

    if (success) {
      // Reset form
      if (!editingExpense) {
        setName('');
        setAmount('');
        setNotes('');
        setType(ExpenseType.NEED);
      }
      setError(null);
      setAdvice(null);
    }
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm mb-6">
      <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
        {editingExpense ? <Edit2Icon /> : <PlusCircleIcon />}
        {editingExpense ? 'تعديل المصرف' : 'إضافة مصرف جديد'}
      </h3>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">

          {/* Name Input with Datalist for Suggestions */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">اسم المصرف</label>
            <input
              list="suggestions"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="مثال: فاتورة الكهرباء"
              required
            />
            <datalist id="suggestions">
              {SUGGESTED_EXPENSES.map((s, i) => <option key={i} value={s} />)}
            </datalist>
          </div>

          {/* Amount */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">المبلغ</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="0.00"
              min="0"
              required
            />
          </div>

          {/* Type */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">النوع (إلزامي)</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as ExpenseType)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white"
            >
              {EXPENSE_TYPES.map(t => (
                <option key={t} value={t}>{t}</option>
              ))}
            </select>
          </div>

          {/* Notes */}
          <div>
             <label className="block text-xs font-semibold text-gray-500 mb-1">ملاحظات</label>
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              placeholder="اختياري"
            />
          </div>
        </div>

        {/* Error & Advice Block */}
        {error && (
          <div className="bg-red-50 border-r-4 border-red-500 p-4 rounded-md animate-pulse">
            <div className="flex items-start">
              <AlertTriangle className="text-red-500 ml-2 mt-0.5" size={18} />
              <div>
                <p className="text-sm font-bold text-red-700">{error}</p>
                {advice && <p className="text-sm text-red-600 mt-1 bg-white/50 p-2 rounded">{advice}</p>}
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-2">
           {editingExpense && (
            <button
              type="button"
              onClick={onCancelEdit}
              className="px-6 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
              <X size={18} />
              إلغاء
            </button>
          )}
          <button
            type="submit"
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-colors flex items-center gap-2"
          >
            {editingExpense ? <Save size={18} /> : <PlusCircle size={18} />}
            {editingExpense ? 'حفظ التعديلات' : 'إضافة المصرف'}
          </button>
        </div>
      </form>
    </div>
  );
};

const Edit2Icon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;
const PlusCircleIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="16"></line><line x1="8" y1="12" x2="16" y2="12"></line></svg>;

import React, { useState, useEffect, useRef } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { Expense, ExpenseType, DashboardMetrics } from './types';
import { GUIDANCE_TEXT, SUGGESTED_EXPENSES } from './constants';
import { Download, Info, AlertCircle } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

// Initial dummy data as requested (but hidden until added, or just as suggestions)
// The prompt said: "Start with the following expenses... amounts zero."
// We will create a helper to populate initial state if empty.

function App() {
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);

  const dashboardRef = useRef<HTMLDivElement>(null);

  // Initialize from LocalStorage or Defaults
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');

    if (savedSalary) setSalary(parseFloat(savedSalary));

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    } else {
      // Initialize with suggestions as per prompt
      const initialExpenses: Expense[] = SUGGESTED_EXPENSES.map((name, index) => ({
        id: `init-${index}`,
        name,
        amount: 0,
        type: ExpenseType.NEED, // Default, user must change
        notes: ''
      }));
      setExpenses(initialExpenses);
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
  }, [expenses, salary]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;

    // Logic: Total Savings = (Salary - Needs - Wants).
    // This includes both explicit "Saving" expenses AND remaining cash.
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    setEditingExpense(null);
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const exportPDF = async () => {
    if (!dashboardRef.current) return;

    const canvas = await html2canvas(dashboardRef.current, {
      scale: 2,
      useCORS: true,
      logging: false,
    });

    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4',
    });

    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
  };

  // 50/30/20 Analysis Text
  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    return (
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
        <AnalysisCard 
          title="الاحتياج (الهدف 50%)" 
          current={needPct} 
          target={50} 
          color="blue" 
          label={ExpenseType.NEED}
        />
        <AnalysisCard 
          title="الرغبات (الهدف 30%)" 
          current={wantPct} 
          target={30} 
          color="amber"
          label={ExpenseType.WANT} 
        />
        <AnalysisCard 
          title="الادخار (الهدف 20%)" 
          current={savePct} 
          target={20} 
          color="emerald" 
          label={ExpenseType.SAVING}
          isMinimum
        />
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-20">
      <StickyHeader salary={salary} metrics={metrics} />

      <main className="max-w-4xl mx-auto px-4" ref={dashboardRef}>

        {/* Salary Input Section */}
        <section className="bg-white rounded-xl shadow-sm p-6 mb-6 border border-gray-200">
          <label className="block text-sm font-bold text-gray-700 mb-2">صافي الراتب الشهري</label>
          <div className="relative">
            <input
              type="number"
              value={salary || ''}
              onChange={(e) => setSalary(parseFloat(e.target.value))}
              placeholder="0"
              className="w-full text-3xl font-bold text-gray-800 border-b-2 border-gray-300 focus:border-blue-600 outline-none py-2 bg-transparent transition-colors"
            />
            <span className="absolute left-0 bottom-3 text-gray-400 font-medium">ريال / عملة محلية</span>
          </div>
        </section>

        {/* Dashboard: Charts & Summary */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-6">
          <div className="lg:col-span-1 bg-white p-4 rounded-xl shadow-sm border border-gray-200">
            <h3 className="font-bold text-gray-700 mb-4 text-center">توزيع الراتب</h3>
            <FinancialChart metrics={metrics} />
          </div>

          <div className="lg:col-span-2">
             {/* 50/30/20 Indicators */}
             {getAnalysis()}

             {/* Quick Stats Box */}
             <div className="bg-indigo-900 text-white rounded-xl p-6 shadow-lg flex flex-col justify-center h-48">
                <h4 className="text-indigo-200 text-sm font-medium mb-1">الادخار والاستثمار الكلي</h4>
                <div className="text-4xl font-bold mb-2">{metrics.totalSavingsCalculated.toLocaleString()}</div>
                <p className="text-xs text-indigo-300 mb-4">يشمل المبالغ المصنفة كادخار + المتبقي من الراتب</p>

                {metrics.remainingSalary > 0 && (
                   <div className="bg-indigo-800/50 rounded px-3 py-2 text-sm flex items-center gap-2">
                      <span className="w-2 h-2 rounded-full bg-green-400"></span>
                      متبقي غير موزع: {metrics.remainingSalary.toLocaleString()}
                   </div>
                )}
             </div>
          </div>
        </div>

        {/* Add/Edit Form - Passively rendered here but hidden in PDF usually (managed by ref scope) */}
        <div data-html2canvas-ignore>
           <AddExpenseForm 
             salary={salary} 
             currentTotal={metrics.totalExpenses} 
             onAdd={handleAddExpense}
             editingExpense={editingExpense}
             onUpdate={handleUpdateExpense}
             onCancelEdit={() => setEditingExpense(null)}
           />
        </div>

        {/* Table */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 mb-8">
          <div className="p-4 border-b border-gray-100 flex justify-between items-center">
             <h3 className="font-bold text-gray-800">تفاصيل المصارف</h3>
             <span className="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded-full">
               {expenses.length} بند
             </span>
          </div>
          <ExpenseTable 
            expenses={expenses} 
            salary={salary} 
            onDelete={handleDeleteExpense} 
            onEdit={setEditingExpense}
          />
        </div>

        {/* Quick Guide */}
        <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 mb-8">
           <div className="flex items-center gap-2 mb-3 text-blue-800">
              <Info size={20} />
              <h3 className="font-bold">إرشادات سريعة</h3>
           </div>
           <p className="text-sm text-blue-700 leading-relaxed whitespace-pre-line">
             {GUIDANCE_TEXT}
           </p>
        </div>

      </main>

      {/* Floating Action Button for Export */}
      <div className="fixed bottom-6 left-6 z-50">
        <button 
          onClick={exportPDF}
          className="bg-gray-800 hover:bg-gray-900 text-white p-4 rounded-full shadow-xl flex items-center gap-2 transition-transform hover:scale-105"
          title="تصدير PDF"
        >
          <Download size={24} />
          <span className="font-bold hidden md:inline">حفظ PDF</span>
        </button>
      </div>

    </div>
  );
}

