type ExpenseType = "NEED" | "WANT" | "SAVING";

type ExpenseRow = {
  name: string;
  amount: number;
  type: ExpenseType;
};

type Props = {
  salary: number;
  expenses: ExpenseRow[];
  remaining: number;
  verseText: string;
  verseRef: string;
  developerName: string;
  developerLogoDataUri?: string;
  exportedAtText: string;
};

function fmt(n: number) {
  try {
    return n.toLocaleString("ar-SA");
  } catch {
    return String(n);
  }
}

function typeLabel(t: ExpenseType) {
  if (t === "NEED") return "احتياج";
  if (t === "WANT") return "رغبة";
  return "ادخار واستثمار";
}

function percentOf(amount: number, salary: number) {
  if (!salary || salary <= 0) return 0;
  return Math.round((amount / salary) * 100);
}

function polarToCartesian(cx: number, cy: number, r: number, angleDeg: number) {
  const a = ((angleDeg - 90) * Math.PI) / 180.0;
  return { x: cx + r * Math.cos(a), y: cy + r * Math.sin(a) };
}

function arcPath(cx: number, cy: number, r: number, startAngle: number, endAngle: number) {
  const start = polarToCartesian(cx, cy, r, endAngle);
  const end = polarToCartesian(cx, cy, r, startAngle);
  const largeArc = endAngle - startAngle <= 180 ? "0" : "1";
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 0 ${end.x} ${end.y} Z`;
}

function PieChartPdf(props: { need: number; want: number; saving: number }) {
  const total = props.need + props.want + props.saving;
  const cx = 55;
  const cy = 55;
  const r = 45;

  const needPct = total > 0 ? props.need / total : 0;
  const wantPct = total > 0 ? props.want / total : 0;
  const savingPct = total > 0 ? props.saving / total : 0;

  const needAngle = needPct * 360;
  const wantAngle = wantPct * 360;
  const savingAngle = savingPct * 360;

  let start = 0;
  const needStart = start;
  const needEnd = start + needAngle;
  start = needEnd;

  const wantStart = start;
  const wantEnd = start + wantAngle;
  start = wantEnd;

  const savingStart = start;
  const savingEnd = start + savingAngle;

  return (
    <View style={styles.chartWrap}>
      <Svg width={120} height={120}>
        <Path d={arcPath(cx, cy, r, needStart, needEnd)} fill="#10b981" />
        <Path d={arcPath(cx, cy, r, wantStart, wantEnd)} fill="#f59e0b" />
        <Path d={arcPath(cx, cy, r, savingStart, savingEnd)} fill="#3b82f6" />
      </Svg>

      <View style={styles.legend}>
        <View style={styles.legendRow}>
          <View style={[styles.legendDot, { backgroundColor: "#10b981" }]} />
          <Text style={styles.legendText}>احتياج</Text>
        </View>
        <View style={styles.legendRow}>
          <View style={[styles.legendDot, { backgroundColor: "#f59e0b" }]} />
          <Text style={styles.legendText}>رغبة</Text>
        </View>
        <View style={styles.legendRow}>
          <View style={[styles.legendDot, { backgroundColor: "#3b82f6" }]} />
          <Text style={styles.legendText}>ادخار واستثمار</Text>
        </View>
      </View>
    </View>
  );
}

