import { pdf } from "@react-pdf/renderer";
import ReportPdf from "./ReportPdf";

async function toDataUriFromPublic(path: string) {
  const res = await fetch(path);
  const blob = await res.blob();
  return await new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result));
    reader.readAsDataURL(blob);
  });
}

async function downloadReportPdf(params: {
  salary: number;
  expenses: Array<{ name: string; amount: number; type: "NEED" | "WANT" | "SAVING" }>;
  remaining: number;
}) {
  const logoDataUri = await toDataUriFromPublic("/ashareef_logo.png");

  const now = new Date();
  const exportedAtText =
    now.toLocaleDateString("ar-SA") + " " + now.toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" });

  const doc = (
    <ReportPdf
      salary={params.salary}
