  const wantPct = total > 0 ? props.want / total : 0;
  const savingPct = total > 0 ? props.saving / total : 0;

  const needAngle = needPct * 360;
  const wantAngle = wantPct * 360;
  const savingAngle = savingPct * 360;

  let start = 0;
  const needStart = start;
  const needEnd = start + needAngle;
  start = needEnd;

  const wantStart = start;
  const wantEnd = start + wantAngle;
  start = wantEnd;

  const savingStart = start;
  const savingEnd = start + savingAngle;

  // Colors match constants.ts
  return (
    <View style={styles.chartWrap}>
      <Svg width={120} height={120}>
        {needAngle > 0 && <Path d={arcPath(cx, cy, r, needStart, needEnd)} fill="#ef4444" />}
        {wantAngle > 0 && <Path d={arcPath(cx, cy, r, wantStart, wantEnd)} fill="#f59e0b" />}
        {savingAngle > 0 && <Path d={arcPath(cx, cy, r, savingStart, savingEnd)} fill="#10b981" />}
