import React from 'react';
import { Trash2, Edit2 } from 'lucide-react';
import { Expense, ExpenseType } from '../types';
import { COLORS } from '../constants';

interface ExpenseTableProps {
  expenses: Expense[];
  salary: number;
  onDelete: (id: string) => void;
  onEdit: (expense: Expense) => void;
}

export const ExpenseTable: React.FC<ExpenseTableProps> = ({ expenses, salary, onDelete, onEdit }) => {

  const getPercentageColor = (amount: number): string => {
    if (salary === 0) return 'bg-gray-100 text-gray-500';
    const percentage = (amount / salary) * 100;
    if (percentage <= 5) return 'bg-green-100 text-green-800';
    if (percentage <= 15) return 'bg-amber-100 text-amber-800';
    return 'bg-red-100 text-red-800';
  };

  const getTypeBadge = (type: ExpenseType) => {
    switch (type) {
      // Changed to Red style
      case ExpenseType.NEED: return <span className="px-2 py-1 rounded-full text-xs bg-red-100 text-red-800 font-medium">احتياج</span>;
      case ExpenseType.WANT: return <span className="px-2 py-1 rounded-full text-xs bg-amber-100 text-amber-800 font-medium">رغبة</span>;
      case ExpenseType.SAVING: return <span className="px-2 py-1 rounded-full text-xs bg-emerald-100 text-emerald-800 font-medium">ادخار</span>;
    }
  };

  return (
    <div className="overflow-x-auto rounded-lg border border-gray-200">
      <table className="w-full text-sm text-right">
        <thead className="bg-gray-50 text-gray-600 font-medium border-b border-gray-200">
          <tr>
            <th className="px-4 py-3">اسم المصروف</th>
            <th className="px-4 py-3">النوع</th>
            <th className="px-4 py-3">المبلغ</th>
            <th className="px-4 py-3">النسبة</th>
            <th className="px-4 py-3">ملاحظات</th>
            <th className="px-4 py-3 text-center">إجراءات</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-100 bg-white">
          {expenses.length === 0 ? (
            <tr>
              <td colSpan={6} className="px-4 py-8 text-center text-gray-400">
                لا توجد مصروفات مضافة حالياً.
              </td>
            </tr>
          ) : (
            expenses.map((expense) => {
              const percentage = salary > 0 ? Math.ceil((expense.amount / salary) * 100) : 0;
              return (
                <tr key={expense.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-4 py-3 font-medium text-gray-900">{expense.name}</td>
                  <td className="px-4 py-3">{getTypeBadge(expense.type)}</td>
                  <td className="px-4 py-3 font-semibold">{expense.amount.toLocaleString()}</td>
                  <td className="px-4 py-3">
                    <span className={`inline-block px-2 py-1 rounded text-xs font-bold ${getPercentageColor(expense.amount)}`}>
                      %{percentage}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-gray-500 max-w-xs truncate">{expense.notes || '-'}</td>
                  <td className="px-4 py-3 flex justify-center gap-2">
                    <button 
                      onClick={() => onEdit(expense)} 
                      className="p-1.5 text-blue-600 hover:bg-blue-50 rounded transition-colors"
                      title="تعديل"
                    >
                      <Edit2 size={16} />
                    </button>
                    <button 
                      onClick={() => onDelete(expense.id)} 
                      className="p-1.5 text-red-600 hover:bg-red-50 rounded transition-colors"
                      title="حذف"
                    >
                      <Trash2 size={16} />
                    </button>
                  </td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Expense, ExpenseType } from '../types';
import { EXPENSE_TYPES, SUGGESTED_EXPENSES } from '../constants';
import { PlusCircle, Save, X, AlertTriangle } from 'lucide-react';

interface AddExpenseFormProps {
  salary: number;
  currentTotal: number;
  expenses: Expense[]; // Added expenses list to analyze for advice
  onAdd: (expense: Omit<Expense, 'id'>) => boolean; 
  editingExpense?: Expense | null;
  onUpdate: (updatedExpense: Expense) => boolean;
  onCancelEdit: () => void;
}

export const AddExpenseForm: React.FC<AddExpenseFormProps> = ({ 
  salary, 
  currentTotal, 
  expenses,
  onAdd, 
  editingExpense,
  onUpdate,
  onCancelEdit
}) => {
  const [name, setName] = useState('');
  const [amount, setAmount] = useState<string>('');
  const [type, setType] = useState<ExpenseType>(ExpenseType.NEED);
  const [notes, setNotes] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [advice, setAdvice] = useState<string | null>(null);

  // Load editing expense data
  useEffect(() => {
    if (editingExpense) {
      setName(editingExpense.name);
      setAmount(editingExpense.amount.toString());
      setType(editingExpense.type);
      setNotes(editingExpense.notes || '');
      setError(null);
      setAdvice(null);
    }
  }, [editingExpense]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name || isNaN(numAmount) || numAmount <= 0) return;

    // Check budget limit
    const amountDiff = editingExpense ? numAmount - editingExpense.amount : numAmount;
    if (currentTotal + amountDiff > salary) {
      const deficit = (currentTotal + amountDiff) - salary;
      setError(`عفواً، إضافة هذا المبلغ ستتجاوز الراتب بمقدار ${deficit.toLocaleString()}.`);

      // --- Smart Expert Advice Logic ---

      // 1. Analyze Current Distribution (excluding the item being edited to avoid double counting)
      const otherExpenses = expenses.filter(e => editingExpense ? e.id !== editingExpense.id : true);

      const currentNeeds = otherExpenses.filter(e => e.type === ExpenseType.NEED).reduce((sum, e) => sum + e.amount, 0);
      const currentWants = otherExpenses.filter(e => e.type === ExpenseType.WANT).reduce((sum, e) => sum + e.amount, 0);

      // Calculate Percentages
      const wantsPct = (currentWants / salary) * 100;

      // 2. Find specific candidates to cut
      // Sort Wants by amount descending
      const largestWant = otherExpenses
        .filter(e => e.type === ExpenseType.WANT)
        .sort((a, b) => b.amount - a.amount)[0];

      // Sort Needs by amount descending
      const largestNeed = otherExpenses
        .filter(e => e.type === ExpenseType.NEED)
        .sort((a, b) => b.amount - a.amount)[0];

      let generatedAdvice = "";

      if (wantsPct > 30 && largestWant) {
        generatedAdvice = `توصية الخبير: إنفاقك على "الرغبات" مرتفع (${Math.round(wantsPct)}% بينما الموصى به 30%). لإتاحة المجال لهذا المصروف، نقترح عليك تقليل بند "${largestWant.name}" بمقدار ${deficit.toLocaleString()}.`;
      } else if (largestWant) {
        generatedAdvice = `توصية الخبير: لإضافة هذا المصروف، ابدأ بتقليل الكماليات. هل يمكنك تخفيض بند "${largestWant.name}"؟`;
      } else if (largestNeed) {
         generatedAdvice = `توصية الخبير: ميزانيتك مضغوطة جداً وتتكون معظمها من احتياجات. راجع بند "${largestNeed.name}" إن كان يمكن استبداله ببديل أقل تكلفة لتوفير ${deficit.toLocaleString()}.`;
      } else {
         generatedAdvice = `توصية الخبير: حاول تقليل أي مصروف آخر بمقدار ${deficit.toLocaleString()} لإتمام العملية.`;
      }

      setAdvice(generatedAdvice);
      return;
    }

    let success = false;
    if (editingExpense) {
      success = onUpdate({ ...editingExpense, name, amount: numAmount, type, notes });
    } else {
      success = onAdd({ name, amount: numAmount, type, notes });
    }

    if (success) {
      // Reset form
      if (!editingExpense) {
        setName('');
        setAmount('');
        setNotes('');
        setType(ExpenseType.NEED);
      }
      setError(null);
      setAdvice(null);
    }
  };

  const handleSuggestionSelect = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (e.target.value) {
      setName(e.target.value);
    }
  };

  const getTypeColorClass = (t: ExpenseType) => {
     switch (t) {
       case ExpenseType.NEED: return 'text-red-700 font-bold';
       case ExpenseType.WANT: return 'text-amber-600 font-bold';
       case ExpenseType.SAVING: return 'text-emerald-600 font-bold';
       default: return 'text-gray-700';
     }
  };

  return (
    <div className="bg-white p-6 rounded-xl shadow-lg w-full max-w-2xl">
      <div className="flex justify-between items-center mb-6 pb-2 border-b border-gray-100">
        <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
          {editingExpense ? <Edit2Icon /> : <PlusCircleIcon />}
          {editingExpense ? 'تعديل المصروف' : 'إضافة مصروف جديد'}
        </h3>
        <button 
          onClick={onCancelEdit}
          className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-100 transition-colors"
        >
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">

          {/* Name Input with Helper Select */}
          <div className="flex flex-col gap-2">
            <div>
              <label className="block text-xs font-semibold text-gray-500 mb-1">اسم المصروف</label>

              <select 
                onChange={handleSuggestionSelect}
                className="w-full mb-2 px-2 py-1.5 text-xs border border-gray-200 bg-gray-50 rounded text-gray-600 focus:border-blue-500 outline-none cursor-pointer"
                defaultValue=""
              >
                <option value="" disabled>↓ اختر من القائمة المقترحة</option>
                {SUGGESTED_EXPENSES.map((s, i) => (
                  <option key={i} value={s}>{s}</option>
                ))}
              </select>

              <input
                type="text"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                placeholder="أو اكتب الاسم هنا..."
                required
                autoFocus={!editingExpense}
              />
            </div>
          </div>

          {/* Amount */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">المبلغ</label>
            <input
              type="number"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all mt-[29px]"
              placeholder="0.00"
              min="0"
              required
            />
          </div>

          {/* Type */}
          <div>
            <label className="block text-xs font-semibold text-gray-500 mb-1">النوع (إلزامي)</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as ExpenseType)}
              className={`w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none bg-white md:mt-[29px] ${getTypeColorClass(type)}`}
            >
              {EXPENSE_TYPES.map(t => (
                <option key={t} value={t} className={getTypeColorClass(t)}>{t}</option>
              ))}
            </select>
          </div>

          {/* Notes */}
          <div>
             <label className="block text-xs font-semibold text-gray-500 mb-1">ملاحظات</label>
            <input
              type="text"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all md:mt-[29px]"
              placeholder="اختياري"
            />
          </div>
        </div>

        {/* Error & Advice Block */}
        {error && (
          <div className="bg-red-50 border-r-4 border-red-500 p-4 rounded-md animate-pulse">
            <div className="flex items-start">
              <AlertTriangle className="text-red-500 ml-2 mt-0.5" size={18} />
              <div>
                <p className="text-sm font-bold text-red-700">{error}</p>
                {advice && <p className="text-sm text-red-600 mt-1 bg-white/50 p-2 rounded">{advice}</p>}
              </div>
            </div>
          </div>
        )}

        <div className="flex justify-end gap-3 pt-4 border-t border-gray-100">
            <button
              type="button"
              onClick={onCancelEdit}
              className="px-6 py-2 rounded-lg border border-gray-300 text-gray-600 hover:bg-gray-50 transition-colors flex items-center gap-2"
            >
              إلغاء
            </button>
          <button
            type="submit"
            className="px-6 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 shadow-md transition-colors flex items-center gap-2"
          >
            {editingExpense ? <Save size={18} /> : <PlusCircle size={18} />}
            {editingExpense ? 'حفظ التعديلات' : 'إضافة المصروف'}
          </button>
        </div>
      </form>
    </div>
  );
};

const Edit2Icon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>;
const PlusCircleIcon = () => <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="16"></line><line x1="8" y1="12" x2="16" y2="12"></line></svg>;

import React, { useState, useEffect } from 'react';
import { StickyHeader } from './components/StickyHeader';
import { FinancialChart } from './components/FinancialChart';
import { ExpenseTable } from './components/ExpenseTable';
import { AddExpenseForm } from './components/AddExpenseForm';
import { PrintableReport } from './components/PrintableReport';
import { Expense, ExpenseType, DashboardMetrics } from './types';
import { GUIDANCE_TEXT } from './constants';
import { Download, Info, AlertCircle, CheckCircle2, Plus } from 'lucide-react';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

function App() {
  const [salary, setSalary] = useState<number>(0);
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [showContent, setShowContent] = useState(false);
  const [isExporting, setIsExporting] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Initialize from LocalStorage or Defaults
  useEffect(() => {
    const savedExpenses = localStorage.getItem('qawam_expenses');
    const savedSalary = localStorage.getItem('qawam_salary');

    if (savedSalary) {
      const s = parseFloat(savedSalary);
      setSalary(s);
      if (s > 0) setShowContent(true);
    }

    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses));
    } else {
      setExpenses([]);
    }
  }, []);

  // Save on Change
  useEffect(() => {
    localStorage.setItem('qawam_expenses', JSON.stringify(expenses));
    localStorage.setItem('qawam_salary', salary.toString());
    if (salary > 0) setShowContent(true);
  }, [expenses, salary]);

  // Calculations
  const metrics: DashboardMetrics = React.useMemo(() => {
    const totalNeeds = expenses.filter(e => e.type === ExpenseType.NEED).reduce((acc, curr) => acc + curr.amount, 0);
    const totalWants = expenses.filter(e => e.type === ExpenseType.WANT).reduce((acc, curr) => acc + curr.amount, 0);
    const totalSavingsExpenses = expenses.filter(e => e.type === ExpenseType.SAVING).reduce((acc, curr) => acc + curr.amount, 0);

    const totalExpenses = totalNeeds + totalWants + totalSavingsExpenses;
    const remainingSalary = salary - totalExpenses;
    const totalSavingsCalculated = Math.max(0, salary - totalNeeds - totalWants);

    return {
      totalNeeds,
      totalWants,
      totalSavingsExpenses,
      totalExpenses,
      remainingSalary,
      totalSavingsCalculated
    };
  }, [expenses, salary]);

  // Handlers
  const handleOpenAddModal = () => {
    setEditingExpense(null);
    setIsModalOpen(true);
  };

  const handleOpenEditModal = (expense: Expense) => {
    setEditingExpense(expense);
    setIsModalOpen(true);
  };

  const handleCloseModal = () => {
    setIsModalOpen(false);
    setTimeout(() => setEditingExpense(null), 300); // Clear after animation
  };

  const handleAddExpense = (newExpenseData: Omit<Expense, 'id'>) => {
    const newExpense = { ...newExpenseData, id: Date.now().toString() };
    setExpenses(prev => [newExpense, ...prev]);
    handleCloseModal();
    return true;
  };

  const handleUpdateExpense = (updatedExpense: Expense) => {
    setExpenses(prev => prev.map(e => e.id === updatedExpense.id ? updatedExpense : e));
    handleCloseModal();
    return true;
  };

  const handleDeleteExpense = (id: string) => {
    setExpenses(prev => prev.filter(e => e.id !== id));
  };

  const handleReset = () => {
    if (window.confirm('هل أنت متأكد من حذف جميع البيانات والبدء من جديد؟')) {
      localStorage.removeItem('qawam_expenses');
      localStorage.removeItem('qawam_salary');
      setSalary(0);
      setExpenses([]);
      setEditingExpense(null);
      setShowContent(false);
      window.scrollTo(0, 0);
    }
  };

  // Robust PDF Export with Multi-page support
  const exportPDF = async () => {
    setIsExporting(true);
    try {
      const input = document.getElementById('printable-report');
      if (!input) {
        throw new Error('Printable report element not found');
      }

      // Generate canvas from the hidden fixed-width container
      const canvas = await html2canvas(input, {
        scale: 2, // High resolution
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff'
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');

      const imgWidth = 210; // A4 Width in mm
      const pageHeight = 297; // A4 Height in mm
      const imgHeight = (canvas.height * imgWidth) / canvas.width;

      let heightLeft = imgHeight;
      let position = 0;

      // First Page
      pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
      heightLeft -= pageHeight;

      // Add extra pages if content overflows
      while (heightLeft > 0) {
        position = heightLeft - imgHeight;
        pdf.addPage();
        pdf.addImage(imgData, 'PNG', 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;
      }

      pdf.save(`QAWAM-Report-${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (err) {
      console.error("PDF Export failed", err);
      alert("حدث خطأ أثناء تصدير PDF. يرجى المحاولة مرة أخرى.");
    } finally {
      setIsExporting(false);
    }
  };

  // 50/30/20 Analysis Logic
  const getAnalysis = () => {
    if (salary === 0) return null;
    const needPct = (metrics.totalNeeds / salary) * 100;
    const wantPct = (metrics.totalWants / salary) * 100;
    const savePct = (metrics.totalSavingsCalculated / salary) * 100;

    const isBalanced = 
      Math.abs(needPct - 50) <= 5 && 
      Math.abs(wantPct - 30) <= 5 && 
      savePct >= 15;

    return (
      <div className="mb-6">
        {isBalanced && (
          <div className="mb-4 bg-emerald-50 border border-emerald-200 rounded-xl p-3 flex items-center gap-3 animate-pulse">
            <div className="bg-emerald-100 p-2 rounded-full text-emerald-600">
              <CheckCircle2 size={24} />
            </div>
            <div>
              <p className="font-bold text-emerald-800">أحسنت! توزيعك المالي متوازن.</p>
              <p className="text-xs text-emerald-600">أنت تلتزم بقاعدة 50/30/20 بشكل ممتاز.</p>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <AnalysisCard 
            title="الاحتياج (الهدف 50%)" 
            current={needPct} 
            target={50} 
            color="red"
            label={ExpenseType.NEED}
          />
          <AnalysisCard 
            title="الرغبات (الهدف 30%)" 
            current={wantPct} 
            target={30} 
            color="amber"
            label={ExpenseType.WANT} 
          />
          <AnalysisCard 
            title="الادخار (الهدف 20%)" 
            current={savePct} 
            target={20} 
            color="emerald" 
            label={ExpenseType.SAVING}
            isMinimum
          />
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-32 relative">
      <StickyHeader salary={salary} metrics={metrics} onReset={handleReset} />

      {/* 
        HIDDEN PRINTABLE REPORT 
        Positioned fixed off-screen to ensure it renders in desktop width (794px)
        even on mobile devices, ensuring high quality PDF export.
      */}
      <div style={{ position: 'fixed', left: '-10000px', top: 0, zIndex: -5, overflow: 'hidden' }}>
        <PrintableReport salary={salary} metrics={metrics} expenses={expenses} />
      </div>

      <main className="max-w-4xl mx-auto px-4">

        {/* Top Section: Salary Input */}
        <div className={`transition-all duration-700 ease-in-out ${salary === 0 ? 'min-h-[60vh] flex flex-col justify-center items-center' : 'mb-6'}`}>

          <div className={`w-full ${salary === 0 ? 'max-w-xl text-center' : 'grid grid-cols-1 md:grid-cols-2 gap-6'}`}>

            {/* Salary Input Card */}
            <section className={`bg-white rounded-2xl shadow-sm border border-gray-200 p-6 relative overflow-hidden transition-all duration-500 ${salary === 0 ? 'shadow-xl scale-105 border-blue-200' : 'h-full flex flex-col justify-center'}`}>

              {salary === 0 && (
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-blue-500 to-emerald-500"></div>
              )}

              <label className={`block font-bold text-gray-800 mb-3 ${salary === 0 ? 'text-xl' : 'text-sm'}`}>
                {salary === 0 ? 'خطوتك الأولى: أدخل صافي راتبك 💰' : 'صافي الراتب الشهري'}
              </label>

              <div className="relative">
                <input
                  type="number"
                  value={salary || ''}
                  onChange={(e) => setSalary(parseFloat(e.target.value))}
                  placeholder="0"
                  autoFocus={salary === 0}
                  className={`w-full font-black text-gray-800 border-b-2 border-gray-200 focus:border-blue-600 outline-none bg-transparent transition-all placeholder-gray-200 ${salary === 0 ? 'text-6xl text-center py-4' : 'text-4xl py-2'}`}
                />
                <span className={`absolute text-gray-400 font-medium ${salary === 0 ? 'left-4 bottom-6 text-lg' : 'left-0 bottom-3'}`}>ريال</span>
              </div>

              <div className={`flex items-start gap-2 mt-4 bg-blue-50/50 p-3 rounded-lg border border-blue-100/50 ${salary === 0 ? 'justify-center' : ''}`}>
                <Info size={16} className="text-blue-500 mt-0.5 shrink-0" />
                <p className="text-xs text-slate-600 font-medium leading-relaxed">
                  المقصود هو الراتب الشهري الصافي الذي يتم إيداعه في الحساب البنكي شهرياً.
                </p>
              </div>
            </section>

            {/* Quick Guide - Only visible when dashboard is active */}
            {salary > 0 && (
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-6 h-full flex flex-col justify-center animate-fade-in">
                <div className="flex items-center gap-2 mb-2 text-blue-800">
                    <Info size={20} />
                    <h3 className="font-bold">إرشادات سريعة</h3>
                </div>
                <p className="text-sm text-blue-700 leading-relaxed whitespace-pre-line">
                  {GUIDANCE_TEXT}
                </p>
              </div>
            )}
          </div>
        </div>

        {/* Dashboard Content - Hidden until Salary > 0 */}
        {showContent && (
          <div className="fade-in space-y-6">

            {/* Charts & Summary */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-1 bg-white p-4 rounded-xl shadow-sm border border-gray-200">
                <h3 className="font-bold text-gray-700 mb-4 text-center">توزيع الراتب</h3>
                <FinancialChart metrics={metrics} />
              </div>

              <div className="lg:col-span-2 flex flex-col gap-6">
                 {/* 50/30/20 Indicators */}
                 {getAnalysis()}

                 {/* Quick Stats Box */}
                 <div className="bg-indigo-900 text-white rounded-xl p-6 shadow-lg flex flex-col justify-center h-full min-h-[140px]">
                    <h4 className="text-indigo-200 text-sm font-medium mb-1">الادخار والاستثمار الكلي</h4>
                    <div className="text-4xl font-bold mb-2">{metrics.totalSavingsCalculated.toLocaleString()} <span className="text-lg font-normal text-indigo-300">ريال</span></div>
                    <p className="text-xs text-indigo-300 mb-4">يشمل المبالغ المصنفة كادخار + المتبقي من الراتب</p>

                    {metrics.remainingSalary > 0 && (
                       <div className="bg-indigo-800/50 rounded px-3 py-2 text-sm flex items-center gap-2 w-fit">
                          <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></span>
                          متبقي غير موزع: {metrics.remainingSalary.toLocaleString()}
                       </div>
                    )}
                 </div>
              </div>
            </div>

            {/* Action Bar (Add Button) */}
            <div data-html2canvas-ignore className="flex justify-end">
              <button 
                onClick={handleOpenAddModal}
                className="w-full md:w-auto bg-blue-600 hover:bg-blue-700 text-white px-6 py-4 rounded-xl shadow-md flex items-center justify-center gap-2 transition-all hover:scale-105 font-bold text-lg"
              >
                <Plus size={24} />
                <span>إضافة مصروف جديد</span>
              </button>
            </div>

            {/* Table */}
            {expenses.length > 0 && (
              <div className="bg-white rounded-xl shadow-sm border border-gray-200 animate-fade-in">
                <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50 rounded-t-xl">
                   <h3 className="font-bold text-gray-800">تفاصيل المصروفات</h3>
                   <span className="text-xs bg-white border border-gray-200 text-gray-600 px-3 py-1 rounded-full shadow-sm">
                     {expenses.length} بند
                   </span>
                </div>
                <ExpenseTable 
