            <div className="text-right">
              <span className="block font-bold text-sm">
                {isExporting ? 'جاري التصدير...' : 'حفظ PDF'}
              </span>
              <span className="block text-[10px] text-slate-300 opacity-80 group-hover:opacity-100">تقرير شامل</span>
            </div>
          </button>
        </div>
      )}

    </div>
  );
}

